/*
	This macro will DELETE all reroll data for one actor chosen from a dropdown.
	It only lists actors that currently have meaningful reroll data stored.

	!!! CAN NOT BE UNDONE !!!
*/

const MODULE_ID = "pf2e-reroll-stats";

if (!game.user?.isGM) {
	ui.notifications.warn("Only a GM can delete reroll data.");
	return;
}

function hasMeaningfulRerollData(stats) {
	if (!stats) return false;

	return (
		(stats.rerollCount ?? 0) > 0 ||
		(stats.betterCount ?? 0) > 0 ||
		(stats.worseCount ?? 0) > 0 ||
		(stats.sameCount ?? 0) > 0 ||
		(stats.successCount ?? 0) > 0 ||
		(stats.critSuccessCount ?? 0) > 0 ||
		(stats.critFailCount ?? 0) > 0
	);
}

const rollData = foundry.utils.deepClone(game.settings.get(MODULE_ID, "rollData") || {});

const actorEntries = Object.entries(rollData)
	.filter(([actorId, actorData]) => {
		const actor = game.actors.get(actorId);
		if (!actor) return false;
		if (!hasMeaningfulRerollData(actorData)) return false;
		return true;
	})
	.map(([actorId, actorData]) => {
		const actor = game.actors.get(actorId);
		return {
			actorId,
			actorName: actor.name,
			actorData
		};
	})
	.sort((a, b) => a.actorName.localeCompare(b.actorName));

if (!actorEntries.length) {
	ui.notifications.info("No actors with reroll data found.");
	return;
}

const optionsHtml = actorEntries.map((entry) => {
	return `<option value="${entry.actorId}">${entry.actorName}</option>`;
}).join("");

function buildPreview(actorId) {
	const data = rollData[actorId];
    const actorName = game.actors.get(actorId)?.name ?? actorId; // get actor name
	if (!data) {
		return `<div>No reroll data found for the selected actor.</div>`;
	}

	return `
        <div><h4>Reroll data for ${actorName}:</h4></div>
		<div><strong>Reroll Count:</strong> ${data.rerollCount ?? 0}</div>
		<div><strong>Better Results:</strong> ${data.betterCount ?? 0}</div>
		<div><strong>Worse Results:</strong> ${data.worseCount ?? 0}</div>
		<div><strong>Same Results:</strong> ${data.sameCount ?? 0}</div>
		<div><strong>Success Count:</strong> ${data.successCount ?? 0}</div>
		<div><strong>Crit Success Count:</strong> ${data.critSuccessCount ?? 0}</div>
		<div><strong>Crit Fail Count:</strong> ${data.critFailCount ?? 0}</div>
	`;
}

const content = `
<form>
	<div class="form-group">
		<label for="reroll-actor-select">Actor</label>
		<select id="reroll-actor-select" name="actorId" style="width: 100%;">
			${optionsHtml}
		</select>
	</div>

	<div
		id="reroll-actor-preview"
		style="border: 1px solid var(--color-border-light-primary);  min-height: 8.5em;"
	>
		${buildPreview(actorEntries[0].actorId)}
	</div>

	<p style="margin-top: 1rem; color: var(--color-text-dark-secondary);">
		This will permanently delete the selected actor's reroll data entry.
	</p>
</form>
`;

const dialog = new foundry.applications.api.DialogV2({
	window: {
		title: "Delete Actor Reroll Data"
	},
	content,
	buttons: [
		{
			action: "delete",
			label: "Delete",
			icon: "fas fa-trash",
			callback: async (event, button, dialogRef) => {
				const form = dialogRef.element.querySelector("form");
				const formData = new FormData(form);
				const actorId = formData.get("actorId");

				if (!actorId || !rollData[actorId]) {
					ui.notifications.warn("Please select an actor with reroll data.");
					return;
				}

				const actorName = game.actors.get(actorId)?.name ?? actorId;

				const confirmed = await foundry.applications.api.DialogV2.confirm({
					window: {
						title: "Confirm Delete"
					},
					content: `<p>This will DELETE the reroll data entry for <strong>${actorName}</strong>. This cannot be undone.</p>`
				});

				if (!confirmed) return;

				delete rollData[actorId];
				await game.settings.set(MODULE_ID, "rollData", rollData);

				const api = game.modules.get(MODULE_ID)?.api ?? globalThis.pf2eRerollStats;
				if (api?.compileActorStatsToJournal) {
					await api.compileActorStatsToJournal();
				}

				dialogRef.close();
				ui.notifications.info(`Deleted reroll data for ${actorName}.`);
			}
		},
		{
			action: "cancel",
			label: "Cancel",
			icon: "fas fa-times"
		}
	]
});

dialog.render(true);

Hooks.once("renderDialogV2", (app, html) => {
	if (app !== dialog) return;

	const select = html.querySelector("#reroll-actor-select");
	const preview = html.querySelector("#reroll-actor-preview");

	if (!select || !preview) {
		ui.notifications.warn("Could not initialize reroll preview UI.");
		return;
	}

	const refreshPreview = () => {
		preview.innerHTML = buildPreview(select.value);
	};

	select.addEventListener("change", refreshPreview);
	refreshPreview();
});
